(function(){"use strict";self.onmessage=async a=>{const{id:e,action:r,data:t,key:n}=a.data;let o,c;try{switch(r){case"encrypt":if(!n)throw new Error("未提供加密密钥");o=await y(t,n);break;case"decrypt":if(!n)throw new Error("未提供加密密钥");o=await h(t,n);break;case"generateChecksum":o=await d(t);break;default:throw new Error(`未知操作: ${r}`)}}catch(i){c=i.message}const s={id:e,result:o,error:c};self.postMessage(s)};async function y(a,e){try{const r=JSON.stringify(a),n=new TextEncoder().encode(r),o=crypto.getRandomValues(new Uint8Array(12)),c=await crypto.subtle.encrypt({name:"AES-GCM",iv:o,tagLength:128},e,n),s=new Uint8Array(o.length+c.byteLength);return s.set(o,0),s.set(new Uint8Array(c),o.length),f(s.buffer)}catch(r){throw console.error("加密错误:",r),new Error("加密数据失败")}}async function h(a,e){try{const r=w(a),t=new Uint8Array(r),n=t.subarray(0,12),o=t.subarray(12),c=await crypto.subtle.decrypt({name:"AES-GCM",iv:n,tagLength:128},e,o),i=new TextDecoder().decode(c);return JSON.parse(i)}catch(r){throw console.error("解密错误:",r),new Error("解密数据失败")}}async function d(a){try{const e=JSON.stringify(a),t=new TextEncoder().encode(e),n=await crypto.subtle.digest("SHA-256",t);return Array.from(new Uint8Array(n)).map(s=>s.toString(16).padStart(2,"0")).join("")}catch(e){throw console.error("校验和生成错误:",e),new Error("生成校验和失败")}}function f(a){const e=new Uint8Array(a);let r="";for(let t=0;t<e.byteLength;t++)r+=String.fromCharCode(e[t]);return btoa(r)}function w(a){const e=atob(a),r=new ArrayBuffer(e.length),t=new Uint8Array(r);for(let n=0;n<e.length;n++)t[n]=e.charCodeAt(n);return r}})();
